class ConfigLoader:
    """Load and save configuration files in various formats."""

    @staticmethod
    def _get_nested_value(data: Dict[str, Any], key_path: str) -> Any:
        """Get a nested value by key path. Supports array indices."""
        parts = ConfigLoader._split_key_path(key_path)
        value = data
        for part in parts:
            if isinstance(value, dict):
                if part in value:
                    value = value[part]
                else:
                    return None
            elif isinstance(value, list):
                # Try to parse as array index
                if part.isdigit():
                    idx = int(part)
                    if 0 <= idx < len(value):
                        value = value[idx]
                    else:
                        return None
                else:
                    # Filter on array
                    matched_items = []
                    for item in value:
                        if isinstance(item, dict) and part in item:
                            matched_items.append(item[part])
                    if len(matched_items) == 1:
                        value = matched_items[0]
                    elif len(matched_items) > 1:
                        # If multiple items match, return the first one
                        # This matches the behavior for template extraction
                        value = matched_items[0]
                    else:
                        return None
            else:
                return None
        return value

    @staticmethod
    def _split_key_path(key_path: str) -> List[str]:
        """
        Split a key path into components, handling array notation.

        Example: 'services[0].name' -> ['services', '[0]', 'name']
        But we want: ['services', '0', 'name'] for easier processing
        """
        parts = []
        i = 0
        current = ""

        while i < len(key_path):
            if key_path[i] == '.':
                if current:
                    parts.append(current)
                current = ""
                i += 1
            elif key_path[i] == '[':
                if current:
                    parts.append(current)
                current = ""
                i += 1
                # Read the array index or filter
                arr_content = ""
                while i < len(key_path) and key_path[i] != ']':
                    arr_content += key_path[i]
                    i += 1
                parts.append(f"[{arr_content}]")
                i += 1  # Skip ']'
            else:
                current += key_path[i]
                i += 1

        if current:
            parts.append(current)

        return parts

